window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["dmv-car"] = window.COURSE_LANG["dmv-car"] || {};
window.COURSE_LANG["dmv-car"]["es"] = [
  {"id":1,"q":"Una señal roja de ocho lados (octágono) siempre significa:","opts":["Detenerse por completo y avanzar cuando sea seguro","Reducir la velocidad y ceder el paso","Prohibido estacionar en todo momento","Cruce de ferrocarril adelante"],"re":"Una señal roja octagonal siempre es PARE (STOP): detente por completo y avanza cuando sea seguro."},
  {"id":2,"q":"Un triángulo rojo y blanco con la punta hacia abajo es una señal de:","opts":["Pare (Stop)","Ceda el paso (Yield) — reduce la velocidad y cede el paso","Prohibida la vuelta en U","Zona de obras"],"re":"El triángulo con la punta hacia abajo es CEDA EL PASO; reduce la velocidad y deja pasar primero al tránsito o a los peatones."},
  {"id":3,"q":"Una señal amarilla en forma de rombo te indica:","opts":["Aquí hay una salida de autopista","Hay servicios disponibles cerca","Estás entrando a una calle de un solo sentido","Una advertencia — un peligro o cambio en el camino más adelante"],"re":"Las señales amarillas en forma de rombo advierten de peligros o cambios adelante, como curvas, incorporaciones o cruces."},
  {"id":4,"q":"Las señales de tránsito de color naranja significan:","opts":["Una zona recreativa","Zona de construcción u obras viales adelante","Un cruce escolar","Un hospital cercano"],"re":"Las señales naranjas indican zonas de construcción y mantenimiento; reduce la velocidad y cuida a los trabajadores."},
  {"id":5,"q":"Una señal de cinco lados (pentágono) indica:","opts":["Una zona donde no se permite rebasar","Un cruce de ferrocarril","Una zona escolar o cruce escolar","Una calle sin salida"],"re":"La forma de pentágono se usa para las señales de zona escolar y cruce escolar."},
  {"id":6,"q":"Una línea amarilla continua de tu lado del camino significa:","opts":["Puedes rebasar cuando esté despejado","Se permite estacionar aquí","Marca un carril para bicicletas","No rebasar — solo puedes cruzarla para dar vuelta a la izquierda"],"re":"Una línea amarilla continua de tu lado significa que no se puede rebasar; solo puedes cruzarla para dar vuelta a la izquierda."},
  {"id":7,"q":"Una luz roja intermitente del semáforo significa:","opts":["Acelerar para despejar la intersección","El semáforo está descompuesto — ignóralo","Detenerse por completo y avanzar cuando sea seguro — como un Pare","Ceder solo a la izquierda"],"re":"Una luz roja intermitente funciona igual que una señal de Pare: detente por completo y avanza cuando sea seguro."},
  {"id":8,"q":"Una luz amarilla fija del semáforo significa:","opts":["La luz está por cambiar a rojo — detente si puedes hacerlo con seguridad","Acelerar para ganarle al rojo","Avanzar — la intersección está despejada","Detenerse y permanecer detenido"],"re":"La luz amarilla fija advierte que el semáforo está por cambiar a rojo; detente si puedes hacerlo con seguridad."},
  {"id":9,"q":"En un alto de cuatro vías, si dos vehículos llegan al mismo tiempo:","opts":["El vehículo de la derecha avanza primero","El vehículo de la izquierda avanza primero","El vehículo más rápido avanza primero","Ambos avanzan al mismo tiempo"],"re":"Cuando dos vehículos llegan al mismo tiempo a un alto de cuatro vías, el de la izquierda cede el paso al de la derecha."},
  {"id":10,"q":"Al entrar a una rotonda (glorieta), debes:","opts":["Detenerte por completo primero","Entrar por la izquierda","Acelerar para incorporarte","Ceder el paso al tránsito que ya circula y entrar por la derecha"],"re":"Cede el paso a los vehículos que ya circulan y entra por la derecha, avanzando en sentido contrario a las manecillas del reloj."},
  {"id":11,"q":"Debes ceder el paso a un peatón en un cruce peatonal:","opts":["Solo si está marcado con pintura","Solo cuando un semáforo lo indique","En cualquier cruce peatonal, marcado o no","Nunca — los peatones ceden el paso a los autos"],"re":"Los conductores deben ceder el paso a los peatones en cualquier cruce, esté pintado (marcado) o no (no marcado)."},
  {"id":12,"q":"Un peatón que cruza con un bastón blanco o un perro guía:","opts":["Siempre tiene el derecho de paso; debes detenerte","Debe ser rebasado rápidamente","Debe esperar a que pasen todos los autos","Puede ser apurado con el claxon"],"re":"Un bastón blanco o un perro guía indican que el peatón es ciego; siempre tienen el derecho de paso y debes detenerte."},
  {"id":13,"q":"Cuando un vehículo de emergencia se acerca con sirena y luces, debes:","opts":["Acelerar para quitarte del camino","Detenerte justo donde estás","Orillarte a la derecha y detenerte hasta que pase","Dar vuelta a la izquierda frente a él"],"re":"Oríllate a la derecha, lejos de las intersecciones, y detente hasta que el vehículo de emergencia haya pasado."},
  {"id":14,"q":"Aun con luz verde, NO debes entrar a una intersección si:","opts":["No puedes cruzarla por completo antes de quedar bloqueado por el tránsito","Hay algún vehículo en sentido contrario","Hay un peatón en la acera de enfrente","Hay un auto pegado detrás de ti"],"re":"Nunca entres a una intersección a menos que puedas despejarla; de lo contrario podrías quedar atrapado y bloquear el tránsito."},
  {"id":15,"q":"Al dar vuelta a la izquierda en una intersección, debes ceder el paso a:","opts":["A nadie — las vueltas a la izquierda tienen prioridad","Solo a los camiones grandes","Solo al auto detrás de ti","Los vehículos en sentido contrario y los peatones cercanos"],"re":"Quien da vuelta a la izquierda debe ceder el paso al tránsito en sentido contrario y a los peatones que estén lo bastante cerca para ser un peligro."},
  {"id":16,"q":"Al entrar a un camino desde una entrada de auto (driveway) o un callejón, debes:","opts":["Tocar el claxon e incorporarte","Detenerte y ceder el paso a todo el tránsito y a los peatones que ya están en el camino","Acelerar para integrarte","Suponer que los demás se detendrán por ti"],"re":"Un vehículo que sale de una entrada, callejón o camino privado debe ceder el paso al tránsito y a los peatones que ya están en la vía."},
  {"id":17,"q":"La 'Ley Básica de Velocidad' de California dice que debes:","opts":["Nunca conducir más rápido de lo que es seguro para las condiciones del momento","Conducir siempre al máximo señalado","Mantenerte 10 mph por debajo del límite","Igualar al auto de adelante"],"re":"La Ley Básica de Velocidad significa que nunca debes conducir más rápido de lo que es seguro para las condiciones, aunque sea por debajo del límite señalado."},
  {"id":18,"q":"Salvo que se indique lo contrario, el límite de velocidad en una zona comercial o residencial es:","opts":["15 mph","25 mph","35 mph","45 mph"],"re":"El límite predeterminado en zonas comerciales y residenciales es 25 mph, salvo que una señal indique otra cosa."},
  {"id":19,"q":"Cerca de una escuela cuando hay niños presentes, el límite de velocidad (salvo que se indique otra cosa) es:","opts":["25 mph","35 mph","45 mph","Sin límite si conduces con cuidado"],"re":"Cerca de una escuela con niños presentes el límite es 25 mph, y 15 mph donde así se señale."},
  {"id":20,"q":"Salvo que se indique lo contrario, el límite máximo de velocidad en la mayoría de las carreteras de California es:","opts":["55 mph","65 mph","75 mph","80 mph"],"re":"El máximo en la mayoría de las carreteras de California es 65 mph (algunas señaladas a 70); las carreteras de dos carriles sin división son de 55 mph."},
  {"id":21,"q":"La 'regla de los tres segundos' sirve para:","opts":["Medir cuánto dura una luz amarilla","Mantener una distancia segura detrás del auto de adelante","Decidir cuándo cambiar el aceite","Medir tu reacción ante una sirena"],"re":"Elige un punto fijo; si lo alcanzas en menos de tres segundos después del auto de adelante, lo sigues demasiado de cerca."},
  {"id":22,"q":"Debes dejar una mayor distancia de seguimiento cuando:","opts":["El camino está seco y despejado","Hay poco tránsito","Está lloviendo o vas detrás de una motocicleta o un camión grande","Vas con retraso"],"re":"Deja más espacio con mal clima, de noche y detrás de motocicletas o camiones, que pueden frenar o moverse de repente."},
  {"id":23,"q":"Antes de cambiar de carril, debes:","opts":["Señalar, revisar los espejos y voltear sobre el hombro para revisar el punto ciego","Confiar solo en los espejos","Cambiarte rápido y tocar el claxon","Pasarte sin mirar"],"re":"Señala, revisa los espejos y voltea sobre el hombro para cubrir el punto ciego que los espejos no muestran."},
  {"id":24,"q":"Para usar un carril compartido (HOV/carpool), debes:","opts":["Llevar prisa","Llevar siempre cuatro o más personas","Conducir un camión comercial","Llevar al menos el número de personas que indican las señales"],"re":"Los carriles HOV exigen el número mínimo de ocupantes señalado; entra y sal solo donde la línea esté discontinua."},
  {"id":25,"q":"Al incorporarte a una autopista, debes:","opts":["Detenerte al final de la rampa y esperar un hueco","Usar la rampa para alcanzar la velocidad del tránsito y luego incorporarte en un hueco","Incorporarte a unas 25 mph","Cruzar todos los carriles de una vez hasta el carril rápido"],"re":"Usa la rampa para igualar la velocidad del tránsito e incorpórate en un espacio; detenerte en la rampa es peligroso."},
  {"id":26,"q":"Puedes rebasar legalmente a otro vehículo cuando:","opts":["Hay una línea amarilla continua de tu lado","Estás a menos de 100 pies de una intersección","Hay una línea amarilla discontinua de tu lado y el camino está despejado","Vas tomando una curva"],"re":"Una línea amarilla discontinua de tu lado permite rebasar cuando es seguro y el carril contrario está despejado."},
  {"id":27,"q":"Al rebasar a otro auto, es ilegal:","opts":["Señalar tu intención","Revisar primero el punto ciego","Regresar a tu carril cuando sea seguro","Exceder el límite de velocidad para lograr el rebase"],"re":"Nunca puedes exceder el límite de velocidad para rebasar; si no puedes rebasar dentro del límite, espera una mejor oportunidad."},
  {"id":28,"q":"En una zona residencial, una vuelta en U se permite:","opts":["En cualquier lugar y a cualquier hora","En una intersección, o donde ninguna señal lo prohíba y puedas ver 200 pies en cada dirección","Solo en la autopista","Nunca, bajo ninguna condición"],"re":"En una zona residencial puedes dar vuelta en U en una intersección, o donde el camino esté despejado 200 pies y ninguna señal lo prohíba."},
  {"id":29,"q":"Un borde de acera (cordón) pintado de ROJO significa:","opts":["Prohibido detenerse, parar o estacionar en todo momento","Una zona de carga de mercancía","Solo para dejar y recoger pasajeros","Solo estacionamiento para personas con discapacidad"],"re":"Los bordes rojos significan prohibido detenerse, parar o estacionar en todo momento."},
  {"id":30,"q":"Un borde de acera pintado de BLANCO significa que solo puedes detenerte:","opts":["Todo el tiempo que quieras","Para cargar o descargar mercancía","Toda la noche","El tiempo justo para recoger o dejar pasajeros o correo"],"re":"Los bordes blancos solo permiten una parada breve para recoger o dejar pasajeros o correo."},
  {"id":31,"q":"¿A cuántos pies de un hidrante (toma de agua) NO puedes estacionar?","opts":["3 pies","10 pies","15 pies","30 pies"],"re":"Es ilegal estacionar a menos de 15 pies de un hidrante."},
  {"id":32,"q":"Al estacionar cuesta abajo junto a la acera, debes girar las ruedas delanteras:","opts":["Hacia la acera (a la derecha)","En sentido contrario a la acera (a la izquierda)","Rectas al frente","La dirección de las ruedas no importa"],"re":"Cuesta abajo, gira las ruedas hacia la acera para que el auto ruede contra ella si se mueve."},
  {"id":33,"q":"Al estacionar cuesta arriba junto a la acera, debes girar las ruedas delanteras:","opts":["Hacia la acera","Rectas al frente","No hay diferencia","En sentido contrario a la acera (a la izquierda), para que el auto ruede de regreso contra ella"],"re":"Cuesta arriba con acera, gira las ruedas en sentido contrario a la acera para que el auto ruede de regreso contra ella; pon siempre el freno de mano."},
  {"id":34,"q":"Antes de dar vuelta, debes señalar de forma continua al menos durante:","opts":["Los últimos 100 pies","Los últimos 10 pies","El largo de un auto","Solo si hay otro auto cerca"],"re":"Señala al menos los últimos 100 pies antes de dar vuelta para que los demás sepan lo que vas a hacer."},
  {"id":35,"q":"Cuando un autobús escolar adelante muestra luces rojas intermitentes y su brazo de alto extendido, debes:","opts":["Rebasar rápido por la izquierda","Bajar a 25 mph y seguir","Detenerte en ambos sentidos hasta que las luces se apaguen (salvo que un camino dividido los separe)","Tocar el claxon y rodearlo"],"re":"Detente en ambos sentidos ante un autobús escolar con luces rojas intermitentes, salvo que una carretera dividida los separe; permanece detenido hasta que las luces se apaguen."},
  {"id":36,"q":"Si no puedes ver los espejos laterales del conductor de un camión, significa que:","opts":["El conductor no puede verte — estás en un punto ciego","El camión no se puede mover","Es seguro quedarte ahí","No significa nada en particular"],"re":"Los camiones grandes tienen puntos ciegos enormes (No-Zones); si no ves los espejos del conductor, el conductor no te ve."},
  {"id":37,"q":"En comparación con un auto, un camión grande necesita:","opts":["Una distancia más corta para detenerse","Más o menos la misma distancia para detenerse","Una distancia mucho mayor para detenerse","Ninguna distancia de frenado"],"re":"Los camiones cargados son pesados y tardan mucho más en detenerse, así que nunca te le cierres por delante."},
  {"id":38,"q":"El camino suele estar MÁS resbaloso:","opts":["Después de varias horas de lluvia constante","Durante la primera lluvia tras una temporada seca","En una tarde calurosa y seca","Solo cuando hay nieve sobre él"],"re":"La primera lluvia tras un periodo seco levanta el aceite y el polvo a la superficie, haciendo el camino especialmente resbaloso."},
  {"id":39,"q":"Si tu auto empieza a derrapar, debes:","opts":["Frenar fuerte y mantener el volante fijo","Soltar el acelerador y dirigir el volante hacia donde quieres que vaya el frente del auto","Girar en sentido contrario y frenar fuerte","Jalar el freno de mano"],"re":"Quita el pie del acelerador y dirige suavemente hacia donde quieres ir; no frenes fuerte."},
  {"id":40,"q":"Con niebla, debes conducir usando:","opts":["Luces altas","Sin luces","Luces de emergencia a velocidad normal","Luces bajas"],"re":"Usa luces bajas con niebla; las luces altas se reflejan en la niebla y dificultan ver."},
  {"id":41,"q":"Estás obligado a encender los faros (luces delanteras):","opts":["Solo cuando ya está totalmente oscuro","Solo en la autopista","Solo cuando otros autos tienen las suyas encendidas","Desde 30 minutos después del atardecer hasta 30 minutos antes del amanecer, y siempre que el clima te obligue a usar los limpiaparabrisas"],"re":"Los faros son obligatorios desde 30 minutos después del atardecer hasta 30 minutos antes del amanecer, y cada vez que debas usar los limpiaparabrisas."},
  {"id":42,"q":"De noche debes bajar las luces altas cuando estés a:","opts":["100 pies de cualquier vehículo","500 pies de un vehículo que viene de frente y 300 pies cuando sigues a otro auto","50 pies de un vehículo que viene de frente","No es necesario bajarlas"],"re":"Baja las luces altas a 500 pies del tránsito que viene de frente y a 300 pies de un vehículo al que sigues."},
  {"id":43,"q":"Para un conductor de 21 años o más, es ilegal conducir con una concentración de alcohol en la sangre (BAC) de:","opts":["0.05% o más","0.08% o más","0.10% o más","Cualquier cantidad detectable"],"re":"El límite para conductores de 21 años o más es 0.08%; los conductores comerciales tienen un límite de 0.04%."},
  {"id":44,"q":"Para un conductor menor de 21 años, es ilegal conducir con un BAC de:","opts":["0.08% o más","0.05% o más","0.01% o más (tolerancia cero)","0.04% o más"],"re":"California tiene tolerancia cero para los menores de 21 años: un BAC de 0.01% o más es ilegal."},
  {"id":45,"q":"Según la ley de 'consentimiento implícito' de California, al conducir aceptas:","opts":["Dejar que la policía registre tu casa","Pagar cada multa sin objetar","Someterte a una prueba química de alcohol o drogas si eres arrestado legalmente","Entregar tu licencia cuando te la pidan"],"re":"El consentimiento implícito significa que conducir equivale a aceptar la prueba química si te arrestan por DUI; negarte conlleva la suspensión de la licencia."},
  {"id":46,"q":"En California, el cinturón de seguridad debe ser usado por:","opts":["Solo el conductor","Solo los ocupantes del asiento delantero","El conductor y todos los pasajeros","Solo los niños menores de 8 años"],"re":"El conductor y todos los pasajeros deben usar cinturón; el conductor es responsable de los pasajeros menores de 16 años."},
  {"id":47,"q":"Un niño debe viajar en una silla de auto o asiento elevador en el asiento trasero hasta que tenga:","opts":["4 años","8 años, o al menos 4 pies 9 pulgadas de estatura","12 años","16 años"],"re":"Los niños menores de 8 años deben usar silla o asiento elevador en el asiento trasero, salvo que midan al menos 4 pies 9 pulgadas."},
  {"id":48,"q":"Al conducir, una persona menor de 18 años puede usar el teléfono celular:","opts":["Solo manos libres","Solo para enviar mensajes","Cuando hay poco tránsito","De ninguna manera"],"re":"Los conductores menores de 18 años no pueden usar el celular de ninguna forma al conducir — ni siquiera manos libres."},
  {"id":49,"q":"La ley 'Move Over' de California dice que al acercarte a un vehículo de emergencia, grúa o de Caltrans detenido con luces intermitentes, debes:","opts":["Acelerar para pasarlo rápido","Detenerte en tu carril","No hacer nada distinto","Reducir la velocidad y, si es seguro, cambiarte un carril"],"re":"Reduce la velocidad y cámbiate un carril ante vehículos de emergencia, grúas o de Caltrans detenidos con luces intermitentes."},
  {"id":50,"q":"Si te ves involucrado en un choque que lesiona a alguien o causa más de $1,000 en daños, debes:","opts":["Irte si no hay policía presente","Esperar una semana y luego reportarlo","Reportarlo solo si fue tu culpa","Detenerte, intercambiar información y reportarlo al DMV en un plazo de 10 días"],"re":"Debes detenerte, intercambiar información y presentar un informe SR-1 ante el DMV dentro de los 10 días de un choque con lesión, muerte o daños mayores a $1,000."}
];
